"""SSA-specific inverse modeling classes.

SSA forward runs, forward problem creation, and the SSA solver factory.
Generic utilities (InvSolver, functionals, reporters) live in
:mod:`PISM.invert.core` and are re-exported here for backwards compatibility.
"""

import PISM

from PISM.logging import logMessage

# Re-export everything from core for backwards compatibility.
# Existing code that does `from PISM.invert.ssa import createTikhonovFunctionals`
# will continue to work.
from PISM.invert.core import *  # noqa: F401,F403

class SSAForwardRun(PISM.ssa.SSARun):

    """Subclass of :class:`PISM.ssa.SSAFromInputFile` for inverse problems.

    The underlying SSA implementation is an :cpp:class:`IP_SSATaucForwardProblem`
    or :cpp:class:`IP_SSAHardavForwardProblem`. This class is responsible for
    assembling a :class:`PISM.model.ModelData` containing the auxiliary data needed
    for solving the SSA (:cpp:class:`Array`'s, :cpp:class:`EnthalpyConverter`, etc.)
    as well as the instance of :cpp:class:`IP_SSATaucForwardProblem` that will solve
    the SSA repeatedly in the course of solving an inverse problem.

    This class is intended to be subclassed by test cases where the data is not
    provided from an input file. See also :class:`SSAForwardRunFromInputFile`.
    """

    def __init__(self, design_var):
        PISM.ssa.SSARun.__init__(self)
        assert(design_var in list(ssa_forward_problems.keys()))
        self.grid = None
        self.config = PISM.Context().config
        self.design_var = design_var
        self.design_var_param = createDesignVariableParam(self.config, self.design_var)
        self.is_regional = False

    def designVariable(self):
        """Return string description of the design variable (e.g. 'tauc' or 'hardness')."""
        return self.design_var

    def designVariableParameterization(self):
        """Return the object that performs zeta-to-design-variable transformation."""
        return self.design_var_param

    def _setFromOptions(self):
        """Initialize internal parameters based on command-line flags.

        Called from :meth:`PISM.ssa.SSARun.setup`.
        """
        self.is_regional = PISM.OptionBool("-regional", "regional mode")

    def _constructSolver(self):
        """Construct the SSA forward problem instance.

        Returns an instance of :cpp:class:`IP_SSATaucForwardProblem` rather than
        a basic :cpp:class:`SSAFEM` or :cpp:class:`SSAFD`.

        Called from :meth:`PISM.ssa.SSARun.setup`.
        """
        md = self.modeldata
        return createSSAForwardProblem(md.grid, md.enthalpyconverter, self.design_var_param, self.design_var)

    def _initSolver(self):
        """Perform one-time initialization of the :cpp:class:`IP_SSATaucForwardProblem`.

        Called from :meth:`PISM.ssa.SSARun.setup`.
        """
        # init() will cache the values of the coefficeints at
        # quadrature points once here. Subsequent solves will then not
        # need to cache these values.
        self.solver.init()


class SSAForwardRunFromInputFile(SSAForwardRun):

    """Subclass of :class:`SSAForwardRun` with data read from an input file.

    The vector data for the run is provided in an input :file:`.nc` file.
    """

    def __init__(self, input_filename, inv_data_filename, design_var):
        """Initialize the forward run from input files.

        Parameters
        ----------
        input_filename : str
            Path to a :file:`.nc` file containing generic PISM model data.
        inv_data_filename : str
            Path to a :file:`.nc` file containing data specific to inversion
            (e.g. observed SSA velocities).
        design_var : str
            Name of the design variable (e.g. ``'tauc'`` or ``'hardav'``).
        """
        SSAForwardRun.__init__(self, design_var)
        self.input_filename = input_filename
        self.inv_data_filename = inv_data_filename

    def _initGrid(self):
        """Initialize grid size and periodicity.

        Called from :meth:`PISM.ssa.SSARun.setup`.
        """

        ctx = PISM.Context().ctx

        if self.is_regional:
            ctx.config().set_string("grid.registration", "corner")
        else:
            ctx.config().set_string("grid.registration", "center")

        self.grid = PISM.Grid.FromOptions(ctx)

    def _initPhysics(self):
        """Set the physics based on command-line flags.

        Overrides :meth:`SSARun._initPhysics`.
        """
        config = self.config

        enthalpyconverter = PISM.EnthalpyConverter(config)

        if PISM.OptionBool("-ssa_glen", "SSA flow law Glen exponent"):
            config.set_string("stress_balance.ssa.flow_law", "isothermal_glen")
            config.scalar_from_option("flow_law.isothermal_Glen.ice_softness", "ice_softness")
        else:
            config.set_string("stress_balance.ssa.flow_law", "gpbld")

        self.modeldata.setPhysics(enthalpyconverter)

    def _initCoefficients(self):
        """Read SSA coefficients from the input file.

        Called from :meth:`PISM.ssa.SSARun.setup`.
        """
        self._allocStdSSACoefficients()

        # Read PISM SSA related state variables
        #
        # Hmmm.  A lot of code duplication with SSAFromInputFile._initCoefficients.

        vecs = self.modeldata.vecs
        thickness = vecs.land_ice_thickness
        bed = vecs.bedrock_altitude
        enthalpy = vecs.enthalpy
        mask = vecs.mask
        surface = vecs.surface_altitude
        sea_level = vecs.sea_level

        sea_level.set(0.0)

        # Read in the PISM state variables that are used directly in the SSA solver
        for v in [thickness, bed, enthalpy]:
            v.regrid(self.input_filename, True)

        # variables mask and surface are computed from the geometry previously read

        gc = PISM.GeometryCalculator(self.config)
        gc.compute(sea_level, bed, thickness, mask, surface)

        grid = self.grid
        config = self.modeldata.config

        # Compute yield stress from PISM state variables
        # (basal melt rate, tillphi, and basal water height) if they are available

        file_has_inputs = (PISM.util.fileHasVariable(self.input_filename, 'bmelt') and
                           PISM.util.fileHasVariable(self.input_filename, 'tillwat') and
                           PISM.util.fileHasVariable(self.input_filename, 'tillphi'))

        if file_has_inputs:
            bmr = PISM.model.createBasalMeltRateVec(grid)
            tillphi = PISM.model.createTillPhiVec(grid)
            tillwat = PISM.model.createBasalWaterVec(grid)
            for v in [bmr, tillphi, tillwat]:
                v.regrid(self.input_filename, True)
                vecs.add(v)

            # The SIA model might need the age field.
            if self.config.get_flag("age.enabled"):
                vecs.age.regrid(self.input_filename, True)

            hydrology_model = config.get_string("hydrology.model")
            if hydrology_model == "null":
                subglacial_hydrology = PISM.NullTransportHydrology(grid)
            elif hydrology_model == "routing":
                subglacial_hydrology = PISM.RoutingHydrology(grid)
            elif hydrology_model == "distributed":
                subglacial_hydrology = PISM.DistributedHydrology(grid)

            if self.is_regional:
                yieldstress = PISM.RegionalDefaultYieldStress(self.modeldata.grid)
            else:
                yieldstress = PISM.MohrCoulombYieldStress(self.modeldata.grid)

            # make sure vecs is locked!
            W = PISM.Scalar(grid, "water_thickness")
            W.set(0.0)
            P = PISM.Scalar(grid, "water_pressure")
            P.set(0.0)
            subglacial_hydrology.init(vecs.tillwat, W, P)

            geometry = PISM.Geometry(grid)
            geometry.sea_level_elevation.copy_from(sea_level)
            geometry.bed_elevation.copy_from(bed)
            geometry.ice_thickness.copy_from(thickness)
            geometry.ensure_consistency(self.config.get_number("geometry.ice_free_thickness_standard"))

            ys_inputs = PISM.YieldStressInputs()
            ys_inputs.geometry = geometry
            ys_inputs.till_water_thickness = vecs.tillwat
            ys_inputs.subglacial_water_thickness = W
            yieldstress.init(ys_inputs)

            vecs.tauc.copy_from(yieldstress.basal_material_yield_stress())
        elif PISM.util.fileHasVariable(self.input_filename, 'tauc'):
            vecs.tauc.regrid(self.input_filename, critical=True)

        if PISM.util.fileHasVariable(self.input_filename, 'ssa_driving_stress_x'):
            vecs.add(PISM.model.createDrivingStressXVec(self.grid))
            vecs.ssa_driving_stress_x.regrid(self.input_filename, critical=True)

        if PISM.util.fileHasVariable(self.input_filename, 'ssa_driving_stress_y'):
            vecs.add(PISM.model.createDrivingStressYVec(self.grid))
            vecs.ssa_driving_stress_y.regrid(self.input_filename, critical=True)

        # read in the fractional floatation mask
        vecs.add(PISM.model.createGroundingLineMask(self.grid))
        vecs.gl_mask.regrid(self.input_filename, critical=False, default_value=0.0)  # set to zero if not found

        if self.config.get_flag("geometry.part_grid.enabled"):
            vecs.add(PISM.model.createIceAreaSpecificVolumeVec(self.grid, "ice_area_specific_volume"))
            vecs.ice_area_specific_volume.regrid(self.input_filename, critical=False, default_value=0.0)  # set to zero if not found
                    
        if self.is_regional:
            vecs.add(PISM.model.createNoModelMaskVec(self.grid), 'no_model_mask')
            vecs.no_model_mask.regrid(self.input_filename, True)
            vecs.add(vecs.surface_altitude, 'usurfstore')

        if self.config.get_flag('stress_balance.ssa.dirichlet_bc'):
            vecs.add(PISM.model.create2dVelocityVec(self.grid, name='_bc', desc='SSA velocity boundary condition'), "vel_bc")
            has_u_bc = PISM.util.fileHasVariable(self.input_filename, 'u_bc')
            has_v_bc = PISM.util.fileHasVariable(self.input_filename, 'v_bc')
            if (not has_u_bc) or (not has_v_bc):
                PISM.verbPrintf(2, self.grid.com, "Input file '%s' missing Dirichlet boundary data u/v_bc; using zero default instead." % self.input_filename)
                vecs.vel_bc.set(0.)
            else:
                vecs.vel_bc.regrid(self.input_filename, True)

            if self.is_regional:
                vecs.add(vecs.no_model_mask, 'vel_bc_mask')
            else:
                vecs.add(PISM.model.createBCMaskVec(self.grid), 'vel_bc_mask')
                bc_mask_name = vecs.vel_bc_mask.metadata().get_string("short_name")
                if PISM.util.fileHasVariable(self.input_filename, bc_mask_name):
                    vecs.vel_bc_mask.regrid(self.input_filename, True)
                else:
                    PISM.verbPrintf(2, self.grid.com, "Input file '%s' missing Dirichlet location mask '%s'.  Default to no Dirichlet locations." % (self.input_filename, bc_mask_name))
                    vecs.vel_bc_mask.set(0)

        # Per-cell weight for the surface-velocity misfit functional.
        # Optional: when absent, the misfit is computed with implicit
        # weight 1 everywhere; provide a 0/1 mask in inv_data to
        # restrict the misfit to cells with trustworthy observations.
        if PISM.util.fileHasVariable(self.inv_data_filename, 'vel_misfit_weight'):
            vecs.add(PISM.model.createVelocityMisfitWeightVec(self.grid))
            vecs.vel_misfit_weight.regrid(self.inv_data_filename, True)
            logMessage("  Using 'vel_misfit_weight' from '%s' "
                       "for the surface-velocity misfit functional.\n"
                       % self.inv_data_filename)
        else:
            logMessage("  No 'vel_misfit_weight' in '%s'; the misfit "
                       "uses weight=1 in every cell (including ice-free "
                       "and no-data pixels).\n"
                       % self.inv_data_filename)


def createInvSSASolver(run, method=None):
    """Create an inverse solver appropriate for the configured inversion method.

    Factory function that returns a solver based on the config variable
    ``inverse.stress_balance.method``.

    Parameters
    ----------
    run : SSAForwardRun or SSAForwardRunFromInputFile
        An instance of :class:`SSAForwardRun` or :class:`SSAForwardRunFromInputFile`.
    method : str, optional
        A string corresponding to config variable ``inverse.stress_balance.method``
        describing the inversion method to be used. If ``None``, the value
        is read from the config.

    Returns
    -------
    InvSSASolver
        An inverse solver instance appropriate for the chosen method.

    Raises
    ------
    RuntimeError
        If the required library (TAO or siple) is not available.
    Exception
        If the method string is not recognized.
    """
    if method is None:
        method = run.config.get_string('inverse.stress_balance.method')
    if method == 'tikhonov_gn':
        from PISM.invert import ssa_gn
        return ssa_gn.InvSSASolver_TikhonovGN(run, method)
    elif method.startswith('tikhonov'):
        try:
            from PISM.invert import ssa_tao
            return ssa_tao.InvSSASolver_Tikhonov(run, method)
        except ImportError:
            raise RuntimeError("Inversion method '%s' requires the TAO library." % method)

    if method == 'sd' or method == 'nlcg' or method == 'ign':
        try:
            from PISM.invert import ssa_siple
            return ssa_siple.InvSSASolver_Gradient(run, method)
        except ImportError:
            raise RuntimeError("Inversion method '%s' requires the siple python library." % method)

    raise Exception("Unknown inverse method '%s'; unable to construct solver.", method)


ssa_forward_problems = {'tauc': PISM.IP_SSATaucForwardProblem,
                        'hardav': PISM.IP_SSAHardavForwardProblem}


def createSSAForwardProblem(grid, ec, design_param, design_var):
    """Create an SSA forward problem instance.

    Parameters
    ----------
    grid : Grid
        The computation grid.
    ec : EnthalpyConverter
        Enthalpy converter instance.
    design_param : IPDesignVariableParameterization
        The design variable parameterization.
    design_var : str
        Name of the design variable (e.g. ``'tauc'`` or ``'hardav'``).

    Returns
    -------
    IP_SSATaucForwardProblem or IP_SSAHardavForwardProblem
        An SSA forward problem instance suitable for the given design variable.

    Raises
    ------
    RuntimeError
        If the design variable is not supported.
    """
    ForwardProblem = ssa_forward_problems[design_var]
    if ForwardProblem is None:
        raise RuntimeError("Design variable %s is not yet supported.", design_var)

    return ForwardProblem(grid, design_param)
